import{_ as a,o as s,c as t,O as n}from"./chunks/framework.0d5b6918.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/product/deliverables.md","filePath":"en/product/deliverables.md","lastUpdated":1776439080000}'),r={name:"en/product/deliverables.md"};function i(l,e,d,o,c,p){return s(),t("div",null,e[0]||(e[0]=[n('<div class="brand-page-shell brand-page-shell--deliverables"><section class="brand-hero"><div><p class="brand-kicker">Customer Delivery Docs &amp; Entry Points</p><h1>Customer Delivery Docs &amp; Entry Points</h1><div class="brand-hero__panel"><span class="brand-pill">Delivery Package</span><strong>Delivery is not just handing over one account. It should explain how the customer keeps using the system, how results are checked, and how future updates continue.</strong><p>The focus here is the actual entries, instructions, and result paths that a customer receives.</p></div><p class="brand-lead"> A standard ExecFabric delivery usually includes <strong>one isolated access entry, one customer-specific capability set, and one documentation entry that stays usable for ongoing work.</strong> That means the package is not only an account sheet. It also includes <strong>result entries, notice entries, customer notes, and update notes.</strong></p><div class="brand-chip-list"><span class="brand-chip">Dedicated URL</span><span class="brand-chip">Accounts &amp; permissions</span><span class="brand-chip">Customer notes</span><span class="brand-chip">Result entry</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="/en/contact.html#lead-form">Discuss formal delivery</a><a class="cta-button" href="./customer-flow.html">View Customer Delivery &amp; Usage</a><a class="cta-button" href="./implementation-training.html">View Implementation &amp; Training Services</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // DELIVERY KIT</span><span>DOC 10</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">deliveryKit</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;site_url&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;account&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;docs_entry&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;result_entry&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">supportEntry</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;platform_notice&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;tenant_notice&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;update_guide&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">handoffGoal</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;usable_after_go_live&#39;</span></span></div><div class="matrix-panel__callout">HANDOVER SHOULD STAY USABLE</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">scope</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">customer_safe</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">entry</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">clear</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">docs</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">included</span></span></div></div></div></section><section class="brand-grid brand-grid--four"><article class="brand-card"><p class="brand-kicker">01</p><h2>Dedicated access entry</h2><p>The customer receives its own URL and login entry instead of sharing one generic backend view with everyone else.</p></article><article class="brand-card"><p class="brand-kicker">02</p><h2>Accounts and baseline permissions</h2><p>The customer receives accounts and permission boundaries for its own space instead of all-platform super-admin access.</p></article><article class="brand-card"><p class="brand-kicker">03</p><h2>Documentation entry</h2><p>The customer receives notes on how to use the platform, how to keep updating it, and where notices or documentation are accessed.</p></article><article class="brand-card"><p class="brand-kicker">04</p><h2>Result and artifact entry</h2><p>If the project includes file processing or result export, the package should also include entries for result viewing and downloading.</p></article></section><section class="brand-card"><p class="brand-kicker">Delivery Table</p><h2>What a customer usually receives in standard delivery</h2><table class="deliverables-table"><thead><tr><th>Delivery item</th><th>What the customer gets / sees</th><th>Purpose</th><th>Always included?</th></tr></thead><tbody><tr><td>Access URL</td><td>Their own login entry</td><td>Enter an isolated customer space</td><td>Usually included in standard delivery</td></tr><tr><td>Login account</td><td>Account, initial password, or initialization method</td><td>Enter the authorized capability range</td><td>Usually included in standard delivery</td></tr><tr><td>Customer-specific capabilities</td><td>The capability list authorized for the current project</td><td>Carry the customer&#39;s real usage scenario</td><td>Usually included in standard delivery</td></tr><tr><td>Customer usage notes</td><td>How to log in, execute, and review results</td><td>Lower the usage barrier after delivery</td><td>Recommended as a fixed inclusion</td></tr><tr><td>Implementation &amp; training notes</td><td>Implementation steps, training targets, and support boundaries</td><td>Help the customer continue using the system clearly after go-live</td><td>Recommended as a fixed inclusion</td></tr><tr><td>Customer script hot-update notes</td><td>How scripts are added or updated later</td><td>Support continuous delivery</td><td>Recommended as a fixed inclusion</td></tr><tr><td>Notice / documentation entry</td><td>Notice entry, customer notice page, or other document entry</td><td>Support long-term customer usage</td><td>Opened per project</td></tr><tr><td>File upload / result download entry</td><td>Upload input files, inspect status, and download results</td><td>Carry file-oriented tasks</td><td>Opened per project</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Document Entry</p><h2>What each document entry is for</h2><ul class="brand-list"><li>Customer usage notes explain how to log in, execute, and inspect results.</li><li>Customer script hot-update notes explain how later update requests should be submitted.</li><li>Notice or customer documentation entries support long-term usage instead of relying only on chat history.</li><li>If the project includes file processing, the result view and result download entries should also be made explicit.</li></ul></article><article class="brand-card"><p class="brand-kicker">Key Points</p><h2>Core coverage of the delivery package</h2><ul class="brand-list"><li>Which entries and notes the customer receives</li><li>How notices, documents, and results are viewed after go-live</li><li>When result download and file-processing entries are included</li><li>How the package supports continued usage after delivery</li></ul></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Training</p><h2>Why implementation and training are also deliverables</h2><ul class="brand-list"><li>Delivery does not end when the pages go live. It ends when the customer knows how to keep using and expanding the system.</li><li>Different roles care about different things, so business owners, tenant admins, general users, and IT operations should be trained separately.</li><li>If the project includes baseline support, the support window and support boundary should also be explained during handoff.</li></ul></article><article class="brand-card"><p class="brand-kicker">Implementation Page</p><h2>Continue with training roles, implementation steps, and support boundaries</h2><p>If you are deciding who learns what after go-live and how far support goes, the implementation page is the clearer next step.</p><p><a href="./implementation-training.html">View Implementation &amp; Training Services</a></p></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Source Boundary</p><h2>Standard delivery is not the same as a source-code buyout</h2><ul class="brand-list"><li>Standard delivery focuses on runnable entries, accounts, documentation, result entries, and the required handoff.</li><li>Even if the customer uses an isolated server or isolated environment, that does not automatically mean a permanent license to the whole repository source.</li><li>Source handoff, buyout, or broader authorization boundaries should be written separately into the quote and contract.</li><li>If the customer asks whether source code is included, move to the dedicated boundary page and confirm it there.</li></ul></article><article class="brand-card"><p class="brand-kicker">Quote Template</p><h2>Continue with source-delivery and authorization boundaries</h2><p>When the discussion has already moved into questions like &quot;does private deployment include source code&quot; or &quot;can source be bought out,&quot; the dedicated boundary page is the more efficient path.</p><p><a href="../materials/source-delivery-boundaries.html">View source-delivery and authorization boundaries</a></p></article></section><section class="brand-card"><p class="brand-kicker">After Go-Live</p><h2>What the customer owns and what the platform owns after go-live</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>Customer side</h3><ul class="brand-list"><li>Log in through the dedicated entry and use capabilities inside the authorized range.</li><li>Confirm whether the business outcome matches the expectation.</li><li>Use the formal request path when scripts need updates or new capabilities are needed.</li></ul></article><article class="brand-card brand-card--nested"><h3>Platform side</h3><ul class="brand-list"><li>Guarantee tenant, permission, and execution boundaries.</li><li>Handle review, registration, authorization, and follow-up update flow.</li><li>Maintain notices, documents, and result entries within the project scope.</li></ul></article></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>Continue with file flow, onboarding preparation, and deployment mode</h2><p class="brand-lead">Once the discussion becomes formal, the focus is usually not abstract positioning anymore. It is aligning delivery, upload flow, and onboarding preparation in one pass.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./customer-flow.html"><span>Flow</span><strong>Customer Delivery &amp; Usage</strong></a><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>Files &amp; Results</strong></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>Onboarding Checklist</strong></a><a class="brand-link-card" href="./deployment.html"><span>Deployment &amp; Delivery Boundaries</span><strong>Deployment &amp; Delivery Boundaries</strong></a><a class="brand-link-card" href="./implementation-training.html"><span>Training</span><strong>Implementation &amp; Training Services</strong></a><a class="brand-link-card" href="../materials/source-delivery-boundaries.html"><span>Boundary</span><strong>Source &amp; Authorization Boundaries</strong></a></div></div></section></div>',1)]))}const h=a(r,[["render",i]]);export{m as __pageData,h as default};
